!function(){try{var e="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{},a=(new e.Error).stack;a&&(e._sentryDebugIds=e._sentryDebugIds||{},e._sentryDebugIds[a]="f8b61745-08be-459a-b462-9aa849bc27d9",e._sentryDebugIdIdentifier="sentry-dbid-f8b61745-08be-459a-b462-9aa849bc27d9")}catch(e){}}();var _global="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{};_global.SENTRY_RELEASE={id:"endfield-returning-user-reward-web@1.0.0"},(self.webpackChunkendfield_returning_user_reward_web=self.webpackChunkendfield_returning_user_reward_web||[]).push([[765],{75765:function(e,a,o){o.r(a),o.d(a,{locale:function(){return d}});var s=o(23068),r=JSON.parse('{"title":"Reconexão do Protocolo","description":"Boas-vindas de volta a Talos-II, Endministrator.","guide":{"character":"Perlica","lines":"Endmin, como foram suas férias? Muitas coisas aconteceram a bordo do Dijiang e nossos operadores da Divisão Médica não paravam de me pedir para lembrar você de se inscrever em seu exame físico! Todos estão com saudades, e eu... eu também estou esperando por você, Endmin.","button":"Reconexão do Protocolo"},"home":{"title":"Reconexão do Protocolo","timeCount":"{{DD}}D {{HH}}H","tabs":{"checkIn":"Login em Reconexão","task":"Tarefas de Reconexão","survey":"Pesquisa de retorno"},"checkIn":{"title":"Login em Reconexão","intro":"Participe do evento [Login em Reconexão] por 7 dias e resgate [Ourubis] × 2000 e outras recompensas!"},"task":{"intro":"Participe do evento [Tarefas de Reconexão] e conclua várias tarefas para adquirir <b>[Permissão para CT Básica] × 4</b> e outras recompensas!","taskStatus":{"claimable":"Resgatar","ongoing":"Incompleto","claimed":"Resgatada"},"claimAvailable":"Resgatar Tudo","currentPoint":"Pontos Atuais","taskContent":{"daily_login":"Faça login no jogo 1 vez por dia (isso pode ser feito 7 vezes)","deploy_factory":"Coloque qualquer instalação da Fábrica do CAI","battle_enemy":"Derrote quaisquer 10 inimigos","clear_stage":"Conclua qualquer Espaço do Protocolo 1 vez","manufacture":"Na Dijiang, resgate produtos de qualquer cabine de produção 1 vez","upgrade_role_level":"Aumente o nível de qualquer operador 1 vez","collect_ore":"Colete qualquer minério 1 vez","trade_goods":"Negocie com qualquer posto avançado 1 vez","buy_goods":"Compre mercadorias de qualquer sistema de Redistribuição do Estoque 1 vez","trade_credit":"Compre mercadorias na Loja de Créditos 1 vez","collect_item":"Colete 8 Boletas Rosas","ap_cost":"Gaste 1000 pontos de Sanidade","boss_challenge":"Conclua qualquer desafio de RE-Crise 1 vez","world_battle":"Aluvião de Energia limpa 1 vez (Aluvião de Energia Temporário também conta)"}},"minimumTimeCount":"< 1 H","survey":{"surveyStatus":{"not_started":"Não iniciada","claimed":"Concluída"},"goToButton":"Ir","unlockText":"Desbloqueia após {{timeCount}}","rewardTip":"Conclua a pesquisa para obter","surveyContent":{"survey_1":"Pesquisa de retorno do primeiro dia","survey_2":"Pesquisa sobre a experiência de retorno"},"callbackModal":{"title":"NOTIFICAÇÃO DO SISTEMA","content":"Acesse a nova página para participar da pesquisa.","button":"Concluído"}}},"rule":{"title":"Detalhes do Evento [Reconexão do Protocolo]","content":"<b>- Requisitos de Participação -</b>\\n<span>· Nível de Autoridade de Endministrator ≥ 3</span>\\n<span>· Conclua a missão principal [Capítulo I Processo Ⅰ: Reinicialização do Vale]</span>\\n<span>· Não fez login no jogo por ≥ 21 dias consecutivos</span>\\n<span>· Participação no último evento [Reconexão do Protocolo] ≥ 42 dias atrás</span>\\n<span>· A duração do status de Retorno do Endministrator é a mesma que o período do evento [Reconexão do Protocolo]</span>\\n\\n<b>- Regras do Evento -</b>\\n<span>· Visitar a página do evento [Reconexão do Protocolo] pela primeira vez fornece uma recompensa de Reconexão do Protocolo, Endministrator.</span>\\n<span>· Durante o evento, visite a página [Reconexão do Protocolo] e ganhe recompensas participando de [Login em Reconexão] e [Tarefas de Reconexão].</span>\\n<span>· Durante o evento, faça logins em [Login em Reconexão] todos os dias para ganhar recompensas. Os logins diários podem ser feitos 7 vezes.</span>\\n<span>· Durante o evento, conclua várias [Tarefas de Reconexão] para ganhar pontos e recompensas do evento. Ganhar pontos suficientes também fornece recompensas extras.</span>\\n<span>A contabilização de dados para [Tarefas de Reconexão] pode sofrer pequenos atrasos. Após concluir os requisitos da tarefa, aguarde de 2 a 5 minutos para que os dados sejam sincronizados.</span>\\n<span>· Todas as recompensas do evento serão enviadas para o seu Correio no jogo. As mensagens de recompensas expiram em 30 dias. Por isso, resgate-a a tempo, Endministrator.</span>\\n<span>· O evento terminará 14 dias após a sua participação e será encerrado às 4h da manhã (horário do servidor).</span>"},"rewardModal":{"title":"Recompensas Obtidas","prompt":"Essas recompensas foram enviadas para seu Correio. Não se esqueça de resgatá-las, Endmin.","pointTitle":"Ganhe Pontos","closeTip":"Clique para fechar","closeTip_PC":"Clique para fechar","closeTip_MB":"Toque para fechar"},"gameItem":{"item_gold":{"name":"T-Creds","usage":"TC para abreviar. Essa moeda é reconhecida e utilizada em muitos lugares.","desc":"Uma moeda popular equipada com tecnologias antifalsificação altamente avançadas. Você sabe que o dinheiro é bom quando pode comprar coisas com ele."},"item_diamond":{"name":"Ourubis","usage":"Um material artificial muitas vezes usado para recrutar operadores.","desc":"Um produto especial da lapidação Origeométrica. Essas pedras são extremamente populares devido à sua beleza e ampla gama de usos."},"item_expcard_stage1_high":{"name":"Registro de Combate Avançado","usage":"Um material que fornece uma grande quantidade de EXP para aumentar o nível de operadores dos níveis 1 a 60.","desc":"Um dispositivo de armazenamento com gravações de vídeo de combate. Os novos operadores podem usá-lo para adquirir conhecimento de combate. Ele também é equipado com simulações de batalhas históricas para que os espectadores possam apreciar melhor a natureza brutal das guerras reais travadas em Talos-II."},"item_weapon_expcard_high":{"name":"Conjunto INSP Armas","usage":"Um material que fornece uma grande quantidade de EXP de Arma.","desc":"Um conjunto de ferramentas de uso único com tecnologia do CAI. Permite realizar a inspeção automatizada e aprofundada de toda a estrutura da arma. Também repara danos internos no material e melhora significativamente o desempenho da arma."},"item_char_break_stage_1_2":{"name":"Protodisco","usage":"Um material que promove os operadores para E1 ou E2.","desc":"Um disco especial fabricado com o Tecnoprotocolo e processos de entalhe de dados padrão. Frequentemente utilizado com outros dispositivos para aliviar eficazmente a fadiga física dos operadores durante o treinamento."},"item_ticketgacha_standard_single":{"name":"Permissão para CT Básica","usage":"Um certificado interno da Endfield Industries. Use-o para realizar 1 caça de talentos em [Caça de Talentos Básica].","desc":"A Endfield Industries possui muitas conexões e recursos em Talos-II. Sempre que a Divisão de RH da Endfield inicia uma caça de talentos em um setor específico da indústria, alguém sempre atende."},"ap_supply_lt_n":{"name":"Potencializador de Sanidade de Emergência","usage":"Use para recuperar 40 de Sanidade. Esse item também tem uma data de validade.","desc":"Uma dose moderada de xarope de Sanidade contida em um pacote para uso emergencial. O desenvolvedor parecia ter adquirido uma fórmula secreta a partir de alguns documentos estranhos que multiplicavam a quantidade de açúcar nesta preparação específica."},"item_bp_double_reward":{"name":"Permissão para Uso de Sanidade","usage":"Use para consumir o dobro de Sanidade e resgatar recompensas em dobro nos modos de jogo que consomem Sanidade. 1 permissão deve ser usada para cada 10 Sanidades consumidas.","desc":"Uma permissão que consome instantaneamente uma enorme quantidade de Sanidade. O esgotamento excessivo da Sanidade é extremamente prejudicial ao físico humano. Antes de prosseguir, você precisará passar por um exame médico completo na Divisão Médica."},"item_char_break_stage_3_4":{"name":"Protoconjunto","usage":"Um material que promove os operadores para E3 ou E4.","desc":"Um disco especial fabricado com o Tecnoprotocolo e processos de entalhe de dados avançados. Frequentemente utilizado com outros dispositivos para aliviar eficazmente a fadiga física dos operadores durante o treinamento."},"item_expcard_stage2_high":{"name":"Portador Cognitivo Avançado","usage":"Um material que fornece uma grande quantidade de EXP para aumentar o nível de operadores de Nv. 61 a 90.","desc":"Uma unidade de armazenamento de dados desenvolvida pela Endfield Industries. Ela é compatível com diversos dispositivos de acesso a dados. Os novos operadores podem usá-la para adquirir conhecimento de combate de forma eficaz. Graças ao suporte oferecido pela Cabala da Tranquilidade, esse portador conta com tecnologia de compressão de dados e, portanto, armazena ainda mais informações."},"item_weapon_break_high":{"name":"Molde de Fundição Pesado","usage":"Um material usado no ajuste fino de armas.","desc":"Um molde de fundição pesado feito utilizando materiais raros. A ativação do Tecnoprotocolo permite que ele melhore a resistência geral dos materiais usados em armas."},"item_char_skill_level_7_12":{"name":"Protoedro","usage":"Um material que faz upgrade das habilidades dos operadores.","desc":"Um poliedro de cristal especial fabricado com Tecnoprotocolo e processos de cristalização avançados. Muitas vezes combinado com outros dispositivos para melhorar a absorção fisiológica de materiais de aperfeiçoamento."},"item_case_bp_selfselect_skillsp_1":{"name":"Caixote de Seleção de Progressão Avançada Ⅰ","usage":"Ao abri-lo, você poderá adquirir um material de progressão avançada de sua escolha.","desc":"Um caixote que contém todos os tipos de materiais de uso geral de alta qualidade. O desempenho de combate dos operadores não é limitado por raça nem experiência em combate. Às vezes, eles só precisam de um pouco de inspiração."}},"errMsg":{"code_2000":"Falha ao enviar recompensas. Aguarde e tente novamente.","rewardClaimed":"Esta recompensa já foi resgatada","code_1002":"O evento está carregando. Aguarde alguns instantes antes de acessar a tela do evento novamente","code_1003":"O evento terminou","networkError":"Erro do serviço"},"gamepad":{"hint":{"confirm":"Confirmar","close":"Desl.","closeCurrent":"Feche esta tela","exit":"Sair da página"}}}'),d={lang:s.ELanguage["pt-br"],text:r,fonts:{}}}}]);
